contracts/AnnotationEscrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/cryptography/MerkleProof.sol";
import "@openzeppelin/contracts/metatx/ERC2771Context.sol";

/**
 * @title AnnotationEscrow
 * @dev Holds USDC in escrow for annotation batches. Supports Gasless Meta-Transactions (EIP-2771).
 */
contract AnnotationEscrow is Ownable, ReentrancyGuard, ERC2771Context {
    IERC20 public paymentToken; // Mock USDC
    address public treasury;
    uint256 public platformFeeBps = 1000; // 10% = 1000 bps

    struct Batch {
        address company;
        uint256 totalAmount;
        address[] annotators;
        bool released;
        bool exists;
        bool inDispute; // Governance flag
    }

    mapping(bytes32 => Batch) public batches;
    mapping(bytes32 => bytes32[]) public annotationHashes; 
    mapping(bytes32 => bytes32) public batchMerkleRoots;
    mapping(bytes32 => bytes32[]) public aiInsightHashes;

    event FundsDeposited(
        bytes32 indexed batchId,
        address indexed company,
        uint256 amount,
        address[] annotators,
        uint256 timestamp
    );

    event RewardIncreased(
        bytes32 indexed batchId,
        uint256 additionalAmount,
        uint256 newTotalAmount
    );

    event BatchDisputed(
        bytes32 indexed batchId,
        address indexed disputedBy
    );

    event FundsReleased(
        bytes32 indexed batchId,
        uint256 totalDistributed,
        uint256 platformFee,
        uint256 timestamp
    );

    event AnnotationRecorded(
        bytes32 indexed batchId,
        address indexed annotator,
        bytes32 annotationHash,
        uint256 timestamp
    );

    event AiInsightRecorded(
        bytes32 indexed batchId,
        bytes32 insightHash,
        uint256 timestamp
    );

    event AnnotationBatchRecorded(
        bytes32 indexed batchId,
        address indexed annotator,
        bytes32 merkleRoot,
        uint256 timestamp
    );

    constructor(
        address _paymentToken,
        address _treasury,
        address _trustedForwarder
    ) 
        Ownable(msg.sender) 
        ERC2771Context(_trustedForwarder) 
    {
        paymentToken = IERC20(_paymentToken);
        treasury = _treasury;
    }

    // Override Context functions to support Meta-Transactions
    function _msgSender() internal view override(Context, ERC2771Context) returns (address) {
        return ERC2771Context._msgSender();
    }

    function _msgData() internal view override(Context, ERC2771Context) returns (bytes calldata) {
        return ERC2771Context._msgData();
    }

    function _contextSuffixLength() internal view override(Context, ERC2771Context) returns (uint256) {
        return ERC2771Context._contextSuffixLength();
    }

    /**
     * @notice Company deposits funds for a batch of annotations
     * @param batchId Unique batch identifier
     * @param amount Total USDC amount to deposit (must be pre-approved)
     */
    function deposit(
        bytes32 batchId,
        uint256 amount
    ) external {
        require(!batches[batchId].exists, "Batch already exists");
        require(amount > 0, "Amount must be > 0");

        // Transfer USDC from company to this contract
        require(
            paymentToken.transferFrom(msg.sender, address(this), amount),
            "Transfer failed"
        );

        batches[batchId] = Batch({
            company: msg.sender,
            totalAmount: amount,
            annotators: new address[](0),
            released: false,
            exists: true,
            inDispute: false
        });

        emit FundsDeposited(batchId, msg.sender, amount, new address[](0), block.timestamp);
    }

    /**
     * @notice Release payment for a batch — splits funds dynamically based on consensus scores
     * @param batchId Batch to release
     * @param annotators Final list of annotators to distribute funds to
     * @param splitBps Array of percentages (in basis points) corresponding to each annotator (must sum to 10000)
     */
    function releasePaymentWithSplits(
        bytes32 batchId,
        address[] calldata annotators,
        uint256[] calldata splitBps
    ) external nonReentrant {
        Batch storage batch = batches[batchId];
        require(batch.exists, "Batch does not exist");
        require(msg.sender == batch.company, "Only the company that deposited can release funds");
        require(!batch.released, "Already released");
        require(annotators.length > 0, "Need at least one annotator");
        require(annotators.length == splitBps.length, "Arrays length mismatch");

        uint256 totalBps = 0;
        for (uint256 i = 0; i < splitBps.length; i++) {
            totalBps += splitBps[i];
        }
        require(totalBps == 10000, "Splits must sum to 10000 (100%)");

        batch.released = true;
        batch.annotators = annotators;

        uint256 totalAmount = batch.totalAmount;
        uint256 fee = (totalAmount * platformFeeBps) / 10000;
        uint256 distributable = totalAmount - fee;

        // Send platform fee to treasury
        require(
            paymentToken.transfer(treasury, fee),
            "Fee transfer failed"
        );

        // Distribute to each annotator based on consensus contribution
        for (uint256 i = 0; i < batch.annotators.length; i++) {
            uint256 payout = (distributable * splitBps[i]) / 10000;
            if (payout > 0) {
                require(
                    paymentToken.transfer(batch.annotators[i], payout),
                    "Annotator transfer failed"
                );
            }
        }

        emit FundsReleased(batchId, distributable, fee, block.timestamp);
    }

    /**
     * @notice Record an annotation hash on-chain for auditability
     * @param batchId Associated batch
     * @param annotationHash SHA-256 hash of the annotation JSON
     */
    function recordAnnotation(
        bytes32 batchId,
        bytes32 annotationHash
    ) external {
        require(batches[batchId].exists, "Batch does not exist");
        annotationHashes[batchId].push(annotationHash);

        emit AnnotationRecorded(batchId, msg.sender, annotationHash, block.timestamp);
    }

    /**
     * @notice Record an AI-generated insight hash for auditability
     */
    function recordAiInsight(
        bytes32 batchId,
        bytes32 insightHash
    ) external {
        require(batches[batchId].exists, "Batch does not exist");
        aiInsightHashes[batchId].push(insightHash);

        emit AiInsightRecorded(batchId, insightHash, block.timestamp);
    }

    /**
     * @notice Record a batch of annotations using a Merkle Root
     * @param batchId Associated batch
     * @param merkleRoot The root of the Merkle Tree containing all annotation hashes
     */
    function recordAnnotationBatch(
        bytes32 batchId,
        bytes32 merkleRoot
    ) external {
        require(batches[batchId].exists, "Batch does not exist");
        batchMerkleRoots[batchId] = merkleRoot;

        emit AnnotationBatchRecorded(batchId, msg.sender, merkleRoot, block.timestamp);
    }

    /**
     * @notice Verify an individual annotation hash against a recorded Merkle Root
     */
    function verifyAnnotation(
        bytes32 batchId,
        bytes32 annotationHash,
        bytes32[] calldata proof
    ) external view returns (bool) {
        bytes32 root = batchMerkleRoots[batchId];
        require(root != bytes32(0), "No Merkle Root recorded for this batch");
        
        return MerkleProof.verify(proof, root, annotationHash);
    }

    // View helpers
    function getBatchAnnotators(bytes32 batchId) external view returns (address[] memory) {
        return batches[batchId].annotators;
    }

    function getAnnotationHashes(bytes32 batchId) external view returns (bytes32[] memory) {
        return annotationHashes[batchId];
    }

    function getAiInsightHashes(bytes32 batchId) external view returns (bytes32[] memory) {
        return aiInsightHashes[batchId];
    }

    function isBatchFunded(bytes32 batchId) external view returns (bool) {
        return batches[batchId].exists && !batches[batchId].released;
    }

    /**
     * @notice Increase the reward for a highly complex batch (Dynamic Pricing)
     */
    function increaseReward(bytes32 batchId, uint256 additionalAmount) external {
        Batch storage batch = batches[batchId];
        require(batch.exists, "Batch does not exist");
        require(!batch.released, "Batch already released");
        require(msg.sender == batch.company, "Only company can increase reward");

        require(paymentToken.transferFrom(msg.sender, address(this), additionalAmount), "Transfer failed");
        
        batch.totalAmount += additionalAmount;
        emit RewardIncreased(batchId, additionalAmount, batch.totalAmount);
    }

    /**
     * @notice Dispute a batch if consensus is contested by Elite-tier review
     */
    function disputeBatch(bytes32 batchId) external onlyOwner {
        Batch storage batch = batches[batchId];
        require(batch.exists, "Batch does not exist");
        require(!batch.released, "Batch already released");
        
        batch.inDispute = true;
        emit BatchDisputed(batchId, msg.sender);
    }
}

